 	Insert Into 
	 XBOLTAPP.PIM_PROC_INST (
		ProcInstNo
       ,ProcessID
       ,ProcModelID
       ,ProcPathID
       ,WBSTypeID
       ,Status
       ,StartTime
       ,DueDate
       ,EndTime
       ,InstanceClass
       ,OwnerID
       ,OwnerTeamID
       ,RegUserID
       ,RegUserTeamID
       ,ProcType
       ,DocCategory
       ,DocumentNo
       ,CreationTime
       ,LastUpdated
       ,LastUser
	) Values(
		  #{instanceNo}
		, #{processID}
		, #{procModelID}
		, #{procPathID}
		, #{WBSTypeID}
		, #{status}
		, #{startTime}
		, #{dueDate}
		, #{endTime}
		, #{instanceClass}
		, #{ownerID}
		, #{ownerTeamID}
		, #{loginUserID}
		, #{loginTeamID}
		, #{procType}
		, #{docCategory}
		, #{documentNo}
		, GetDate()
		, GetDate()
		, #{loginUserID}
	 )

mapper.update:
 	Update XBOLTAPP.PIM_INSTANCE_ATTR Set
		Value = #{value}
		, Lastuser = #{lastUser}
		, LastUpdated = GetDate()
	Where instanceNo = #{instanceNo}
	And InstanceClass = #{InstanceClass}
	And AttrTypeCode = #{attrTypeCode}

 	Update XBOLTAPP.PIM_PROC_INST Set
		ProcInstNo = #{ProcInstNo}
		,LastUser = #{lastUser}
		,LastUpdated = GetDate()
	Where ProcInstanceID = #{procInstanceID}

mapper.insert:
 	Insert Into 
	 XBOLTAPP.PIM_ELM_INST (
        ElmInstNo
	   ,ProcInstNo
	   
	   ,SortNum
	   
       ,ElmItemID
       
       ,ElementID
       
       ,Status
       ,ParentElmInstNo
	   
       ,ReqStartDate
       
 	   
       ,ReqDueDate
       
	   
       ,PreElmInstNo
       
        
	   ,RoleID
	   
	    
	   ,UseCaseID
	   
	   
	   ,SchStartDate
	   
	   ,Creator
	   ,CreationTime
	   ,LastUpdated
	) Values(
		  #{newElmInstID}
		, #{ProcInstNo}
		
		, #{sortNum}
		
		, #{elmItemID}
		
		, #{elementID}
       
		, #{status}
		, #{ParentElmInstNo}
	    
		, #{startDate}
        
	    
		, #{endDate}
        
	    
        , #{PreElmInstNo}
        
        
        , #{roleID}
        
        
	   , #{useCaseID}
	   
        
        , #{SchStartDate}
        
         
        , #{creator}
        , GetDate()
        
        , GetDate()
	 )

mapper.update:
UPDATE XBOLTAPP.PIM_ELM_INST
   SET ReqStartDate = #{startDate}, ReqDueDate = #{endDate}
 WHERE ElmInstNo = #{ElmInstNo}

 	UPDATE XBOLTAPP.PIM_ELM_INST
	   SET ReqStartDate = A.ReqStartDate, ReqDueDate = A.ReqDueDate
	  FROM XBOLTAPP.PIM_ELM_INST TIS
	       Left Outer Join (
		   SELECT MIN(ReqStartDate) AS ReqStartDate, MAX(ReqDueDate) AS ReqDueDate, ParentInstNo
			 FROM XBOLTAPP.PIM_ELM_INST 
			WHERE ParentElmInstNo = #{ElmInstNo}
			      GROUP BY ParentElmInstNo 
	       )A ON TIS.ElmInstNo = A.ParentElmInstNo
 	 WHERE TIS.ElmInstNo = #{ElmInstNo}
